public class RefSemantics {
    static class Node {
        int val;
        Node(int v) { val = v; }
    }
    static void doubleIt(Node n) {
        n.val *= 2;    // mutates the object
    }
    static void replace(Node n) {
        n = new Node(999);  // rebinds local only
    }
    public static void main(String[] args) {
        Node x = new Node(5);
        doubleIt(x);
        System.out.println(x.val);
        replace(x);
        System.out.println(x.val);
    }
}
